// ── Barra de formatação flutuante (aparece ao selecionar texto) ──
(function setupFloatingFormatBar() {
  const bar = document.createElement('div');
  bar.id = 'fmt-bar';
  bar.style.cssText = [
    'position:fixed','z-index:99999','display:none','flex-direction:row',
    'gap:4px','align-items:center','padding:5px 8px',
    'background:#1c1c1c','border-radius:7px',
    'box-shadow:0 3px 12px rgba(0,0,0,0.35)',
    'pointer-events:auto'
  ].join(';');

  const makeBtn = (label, cmd) => {
    const b = document.createElement('button');
    b.type = 'button';
    b.textContent = label;
    b.style.cssText = [
      'background:transparent','border:1px solid #555','color:#fff',
      'border-radius:5px','padding:3px 11px','cursor:pointer',
      'font-size:14px','line-height:1.5',
      label === 'N' ? 'font-weight:700' : 'font-style:italic'
    ].join(';');
    b.addEventListener('mousedown', e => {
      e.preventDefault();
      e.stopPropagation();
      document.execCommand(cmd);
    });
    return b;
  };

  bar.appendChild(makeBtn('N', 'bold'));
  bar.appendChild(makeBtn('I', 'italic'));
  document.body.appendChild(bar);

  function show(rect) {
    bar.style.display = 'flex';
    // position:fixed usa coordenadas do viewport — sem scrollY
    const top = rect.top < 50 ? rect.bottom + 6 : rect.top - 44;
    const left = Math.max(8, rect.left + rect.width / 2 - 44);
    bar.style.top  = top  + 'px';
    bar.style.left = left + 'px';
  }

  function hide() { bar.style.display = 'none'; }

  document.addEventListener('selectionchange', () => {
    const sel = window.getSelection();
    if (!sel || sel.isCollapsed || !sel.rangeCount) { hide(); return; }
    const node = sel.anchorNode?.nodeType === 3
      ? sel.anchorNode.parentElement
      : sel.anchorNode;
    if (!node?.closest('.ai-result, #planoTratamento')) { hide(); return; }
    const rect = sel.getRangeAt(0).getBoundingClientRect();
    if (rect.width === 0) { hide(); return; }
    show(rect);
  });
})();

function injectFormatBar(resultEl) { /* barra agora é global — nada a fazer por elemento */ }

// ── Navigation ────────────────────────────────────────────────
function navigate(dir) {
  const next = currentSection + dir;
  if (next < 1 || next > TOTAL_SECTIONS) return;
  document.getElementById(`section${currentSection}`).classList.remove('active');
  currentSection = next;
  if (currentSection > maxVisited) maxVisited = currentSection;
  document.getElementById(`section${currentSection}`).classList.add('active');
  updateNav();
  window.scrollTo({ top: 0, behavior: 'smooth' });
}

function goToSection(n) {
  if (n < 1 || n > TOTAL_SECTIONS) return;
  document.getElementById(`section${currentSection}`).classList.remove('active');
  currentSection = n;
  if (currentSection > maxVisited) maxVisited = currentSection;
  document.getElementById(`section${currentSection}`).classList.add('active');
  updateNav();
  window.scrollTo({ top: 0, behavior: 'smooth' });
}

function updateNav() {
  document.getElementById('sectionLabel').textContent = `Seção ${currentSection} de ${TOTAL_SECTIONS}`;

  document.querySelectorAll('.progress-seg').forEach(seg => {
    const n = parseInt(seg.dataset.section);
    seg.classList.remove('visited', 'current');
    if (n === currentSection) {
      seg.classList.add('current');
    } else if (n <= maxVisited) {
      seg.classList.add('visited');
    }
  });

  const back = document.getElementById('btnBack');
  const next = document.getElementById('btnNext');
  back.style.display = currentSection === 1 ? 'none' : '';

  if (currentSection === TOTAL_SECTIONS) {
    next.style.display = 'none';
  } else {
    next.style.display = '';
  }

}

