// ── Result buttons ────────────────────────────────────────────
// Tests that reveal a Tipo 1/2/3 sub-row when result is positive
document.addEventListener('click', e => {
  const btn = e.target.closest('.result-btn');
  if (!btn) return;
  const test = btn.dataset.test;

  // btn-multi: toggle individual, independente dos outros
  if (btn.classList.contains('btn-multi')) {
    btn.classList.toggle('active');
    if (btn.classList.contains('active')) {
      testResults[test] = btn.dataset.val;
    } else {
      delete testResults[test];
    }
    // Discinesia: lógica de exclusão mútua entre Negativo e Positivo D/E
    if (test === 'discinese-neg') {
      if (btn.classList.contains('active')) {
        // Neg ativado: limpar D e E e seus tipos
        ['d', 'e'].forEach(lado => {
          document.querySelector(`.result-btn[data-test="discinese-${lado}"]`)?.classList.remove('active');
          delete testResults[`discinese-${lado}`];
          document.getElementById(`discinese-tipo-${lado}`)?.classList.add('hidden');
          document.querySelectorAll(`.result-btn[data-test="discinese-tipo-${lado}"]`).forEach(b => b.classList.remove('active'));
          delete testResults[`discinese-tipo-${lado}`];
        });
      }
    } else if (test === 'discinese-d' || test === 'discinese-e') {
      if (btn.classList.contains('active')) {
        // Positivo ativado: limpar Negativo
        document.querySelector('.result-btn[data-test="discinese-neg"]')?.classList.remove('active');
        delete testResults['discinese-neg'];
      }
      const lado = test.split('-')[1];
      const tipoEl = document.getElementById(`discinese-tipo-${lado}`);
      if (tipoEl) {
        tipoEl.classList.toggle('hidden', !btn.classList.contains('active'));
        if (!btn.classList.contains('active')) {
          document.querySelectorAll(`.result-btn[data-test="discinese-tipo-${lado}"]`).forEach(b => b.classList.remove('active'));
          delete testResults[`discinese-tipo-${lado}`];
        }
      }
    }
    return;
  }

  // Seleção única dentro do grupo
  document.querySelectorAll(`.result-btn[data-test="${test}"]`).forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  testResults[test] = btn.dataset.val;
});

// ── Photo handling ────────────────────────────────────────────
function isHeicFile(file) {
  return /\.(heic|heif)$/i.test(file.name) ||
    file.type === 'image/heic' ||
    file.type === 'image/heif';
}

async function fixImageOrientation(dataUrl) {
  try {
    const res = await fetch(dataUrl);
    const blob = await res.blob();
    const bitmap = await createImageBitmap(blob, { imageOrientation: 'from-image' });
    const canvas = document.createElement('canvas');
    canvas.width = bitmap.width;
    canvas.height = bitmap.height;
    canvas.getContext('2d').drawImage(bitmap, 0, 0);
    bitmap.close();
    return canvas.toDataURL('image/jpeg', 0.92);
  } catch (e) {
    return dataUrl;
  }
}


function resizeImageToBase64(dataUrl, maxDim, quality) {
  return new Promise(resolve => {
    const img = new Image();
    img.onload = () => {
      let w = img.naturalWidth, h = img.naturalHeight;
      if (w > maxDim || h > maxDim) {
        if (w >= h) { h = Math.round(h * maxDim / w); w = maxDim; }
        else { w = Math.round(w * maxDim / h); h = maxDim; }
      }
      const canvas = document.createElement('canvas');
      canvas.width = w; canvas.height = h;
      canvas.getContext('2d').drawImage(img, 0, 0, w, h);
      const out = canvas.toDataURL('image/jpeg', quality);
      resolve({ dataUrl: out, base64: out.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.src = dataUrl;
  });
}

function storePhoto(key, file) {
  const reader = new FileReader();
  reader.onload = async ev => {
    const corrected = await fixImageOrientation(ev.target.result);
    photoData[key] = { dataUrl: corrected, base64: corrected.split(',')[1], mimeType: 'image/jpeg' };
    const preview = document.getElementById(`preview${key}`);
    const placeholder = document.getElementById(`placeholder${key}`);
    if (preview) { preview.src = corrected; preview.classList.add('visible'); }
    if (placeholder) placeholder.classList.add('hidden');
  };
  reader.readAsDataURL(file);
}

async function handlePhoto(input, key) {
  let file = input.files[0];
  if (!file) return;

  if (isHeicFile(file)) {
    showToast('Convertendo HEIC para JPEG…');
    try {
      const blob = await heic2any({ blob: file, toType: 'image/jpeg', quality: 0.88 });
      file = new File([blob], file.name.replace(/\.(heic|heif)$/i, '.jpg'), { type: 'image/jpeg' });
    } catch (err) {
      showToast(`Erro ao converter HEIC: ${err.message}`);
      return;
    }
  }

  storePhoto(key, file);
}

// ── AI Photo Analysis ─────────────────────────────────────────
const VIEW_LABELS = {
  Anterior:   'Vista Anterior',
  Posterior:  'Vista Posterior',
  LateralD:   'Vista Lateral Direita',
  LateralE:   'Vista Lateral Esquerda',
  Flexao:     'Flexão Global',
  Extensao:   'Extensão Global',
  FlexaoLatD: 'Flexão Lateral Direita',
  FlexaoLatE: 'Flexão Lateral Esquerda',
  RotacaoD:   'Rotação Direita',
  RotacaoE:   'Rotação Esquerda',
};
const CHAIN_KEYS = new Set(['Flexao', 'Extensao', 'FlexaoLatD', 'FlexaoLatE', 'RotacaoD', 'RotacaoE']);
const PAIR_MAP = {
  FlexaoLatD: 'FlexaoLatE',
  FlexaoLatE: 'FlexaoLatD',
  RotacaoD:   'RotacaoE',
  RotacaoE:   'RotacaoD',
};

function coletarContextoClinico() {
  const v = id => (document.getElementById(id)?.value || '').trim();
  const parts = [];
  const add = (label, val) => { if (val) parts.push(`${label}: ${val}`); };
  add('Objetivo terapêutico', v('objetivo'));
  add('Queixa principal', v('queixaPrincipal'));
  add('História da doença atual', v('hda'));
  add('Diagnóstico clínico', v('diagnostico'));
  add('O que piora', v('piora'));
  add('O que melhora', v('melhora'));
  add('Antecedentes patológicos', v('app'));
  return parts.join('\n');
}

function buildPosturalPrompt(vista, ctx) {
  const ctxBlock = ctx
    ? `\nDADOS CLÍNICOS DO PACIENTE (use apenas o que foi fornecido — nunca acrescente informações ausentes):\n${ctx}\n`
    : '';
  const dir3 = ctx
    ? 'Cruze explicitamente os dados clínicos fornecidos com os achados visuais — se o paciente relata dor em determinada região e há uma alteração postural correspondente visível, conecte os dois de forma fundamentada.'
    : 'Limite a análise ao que é efetivamente visível na imagem.';

  return `Você é um fisioterapeuta especialista em análise postural. Analise esta fotografia — <strong>${vista}</strong> — seguindo rigorosamente as diretrizes abaixo.
${ctxBlock}
<strong>Convenção de lateralidade:</strong> nas vistas anterior e posterior, o lado DIREITO do paciente aparece no lado ESQUERDO da imagem (como em um espelho). Use sempre o referencial do paciente, não do observador.

<strong>Tom:</strong> escreva de forma clara e direta, como para uma colega fisioterapeuta. Frases curtas e objetivas — use terminologia técnica quando for mais precisa do que uma descrição simples, mas evite jargão desnecessário.

DIRETRIZES:

1. Descreva apenas o que é efetivamente visível na imagem. Se algum achado não for claramente observável, declare isso explicitamente. Nunca invente ou presuma informações ausentes.

2. Para cada alteração identificada, estruture a análise em três partes:
   — <strong>Achado visual:</strong> descrição objetiva e precisa (ex.: anteriorização da cabeça, elevação do ombro direito, hiperlordose lombar acentuada).
   — <strong>Causas biomecânicas e musculares prováveis:</strong> quais estruturas estão provavelmente envolvidas com base no padrão observado.
   — <strong>Consequências funcionais e sintomatológicas:</strong> sobrecargas articulares, compensações em cadeia, possíveis dores e limitações decorrentes.

3. ${dir3}

4. Para cada alteração, inclua uma <strong>sugestão breve de abordagem pelo movimento</strong> (ex.: mobilização articular, fortalecimento de estabilizadores, alongamento de cadeias anteriores, reeducação respiratória) — sem detalhar exercícios específicos, pois o plano completo é gerado em outra etapa.

5. Utilize como referencial as cadeias musculares e os trilhos anatômicos. Não cite autores, livros ou obras no texto gerado.

6. <strong>Formatação:</strong> use <strong>...</strong> para negritos. Não use asteriscos (**). Estruture em tópicos claros com quebras de linha entre eles.

7. Finalize com um parágrafo de <strong>Análise</strong> integrando os principais achados desta vista.

Responda em português.`;
}

function buildChainPrompt(movimento, ctx, comparacao = null) {
  const ctxBlock = ctx
    ? `\nDADOS CLÍNICOS DO PACIENTE (use apenas o que foi fornecido — nunca acrescente informações ausentes):\n${ctx}\n`
    : '';
  const dir3 = ctx
    ? 'Cruze explicitamente os dados clínicos fornecidos com os achados visuais — se o paciente relata dor em determinada região e há tensão ou limitação correspondente visível, conecte os dois de forma fundamentada.'
    : 'Limite a análise ao que é efetivamente visível na imagem.';
  const comparacaoBlock = comparacao
    ? `\n<strong>ANÁLISE DO MOVIMENTO CONTRALATERAL JÁ REALIZADA (use exclusivamente para comparação na diretriz 8):</strong>\n${comparacao}\n`
    : '';
  const dir8 = comparacao
    ? `\n8. <strong>Comparação com o lado contralateral:</strong> ao final, adicione um parágrafo intitulado <strong>Comparação entre os lados</strong> comparando os achados deste movimento com os do movimento contralateral acima. Identifique se há simetria ou assimetria, destaque as diferenças clinicamente relevantes e indique o que o padrão bilateral sugere sobre as restrições predominantes do paciente.`
    : '';

  return `Você é um fisioterapeuta especialista em cadeias musculares e trilhos anatômicos. Analise esta fotografia — <strong>${movimento}</strong> — seguindo rigorosamente as diretrizes abaixo.
${ctxBlock}${comparacaoBlock}
<strong>Convenção de lateralidade:</strong> nas vistas anterior e posterior, o lado DIREITO do paciente aparece no lado ESQUERDO da imagem (como em um espelho). Use sempre o referencial do paciente, não do observador.

<strong>Tom:</strong> escreva de forma clara e direta, como para uma colega fisioterapeuta. Frases curtas e objetivas — use terminologia técnica quando for mais precisa do que uma descrição simples, mas evite jargão desnecessário.

DIRETRIZES:

1. Descreva apenas o que é efetivamente visível na imagem. Se algum achado não for claramente observável, declare isso explicitamente. Nunca invente ou presuma informações ausentes.

2. Para cada achado identificado, estruture a análise em quatro partes:
   — <strong>Localização exata:</strong> descreva com precisão a região anatômica onde a tensão, encurtamento, retificação ou curva excessiva é observada (ex.: retificação da lordose lombar, tensão no terço superior do trapézio direito, limitação na cadeia posterior a partir dos isquiotibiais bilateralmente).
   — <strong>Cadeias e trilhos envolvidos:</strong> identifique quais cadeias musculares e trilhos anatômicos estão manifestando tensão ou insuficiência com base no padrão observado.
   — <strong>Causas biomecânicas prováveis:</strong> mecanismos musculares e articulares geradores do padrão identificado.
   — <strong>Consequências funcionais e sintomatológicas:</strong> sobrecargas, compensações em cadeia, possíveis dores e limitações decorrentes.

3. ${dir3}

4. Para cada achado, inclua uma <strong>sugestão breve de abordagem pelo movimento</strong> — sem detalhar exercícios específicos, pois o plano completo é gerado em outra etapa.

5. Utilize como referencial as cadeias musculares e os trilhos anatômicos. Não cite autores, livros ou obras no texto gerado.

6. <strong>Formatação:</strong> use <strong>...</strong> para negritos. Não use asteriscos (**). Estruture em tópicos claros com quebras de linha entre eles.

7. Finalize com um parágrafo de <strong>Análise</strong> sobre o padrão geral de tensão identificado neste movimento.
${dir8}
Responda em português.`;
}

async function analisarFoto(key) {
  if (!photoData[key]) {
    showToast('Adicione uma foto antes de analisar.');
    return;
  }

  const resultEl = document.getElementById(`result${key}`);
  const ctx    = coletarContextoClinico();
  const vista  = VIEW_LABELS[key] || key;

  // Se for um teste com par contralateral e o par já foi analisado, passa o texto para comparação
  let comparacao = null;
  const parKey = PAIR_MAP[key];
  if (parKey) {
    const parEl = document.getElementById(`result${parKey}`);
    const parTexto = parEl?.textContent?.trim();
    if (parTexto && !parTexto.startsWith('Analisando') && parEl.classList.contains('visible')) {
      const parTextoLimitado = parTexto.length > 2000 ? parTexto.slice(0, 2000) + '…' : parTexto;
      comparacao = `[${VIEW_LABELS[parKey]}]\n${parTextoLimitado}`;
    }
  }

  const prompt = CHAIN_KEYS.has(key) ? buildChainPrompt(vista, ctx, comparacao) : buildPosturalPrompt(vista, ctx);

  resultEl.className = 'ai-result visible loading';
  resultEl.textContent = 'Analisando com IA...';

  const { base64, mimeType } = await resizeImageToBase64(photoData[key].dataUrl, 800, 0.6);

  try {
    const resp = await fetch('/api/ia', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'claude-sonnet-4-6',
        max_tokens: 4096,
        messages: [{
          role: 'user',
          content: [
            { type: 'image', source: { type: 'base64', media_type: mimeType, data: base64 } },
            { type: 'text', text: prompt }
          ]
        }]
      })
    });

    if (!resp.ok) {
      const err = await resp.json().catch(() => ({}));
      throw new Error(err.error?.message || `Erro ${resp.status}`);
    }

    const data = await resp.json();
    const text = data.content?.[0]?.text || 'Sem resposta.';
    resultEl.className = 'ai-result visible';
    resultEl.contentEditable = 'true';
    resultEl.innerHTML = text.replace(/\n/g, '<br>');
    injectFormatBar(resultEl);
    salvarRascunho();

    // Botão "Resumir análise"
    let resumirBtn = document.getElementById(`resumirAnaliseBtn${key}`);
    if (!resumirBtn) {
      resumirBtn = document.createElement('button');
      resumirBtn.type = 'button';
      resumirBtn.id = `resumirAnaliseBtn${key}`;
      resumirBtn.className = 'btn-resumir-analise';
      resumirBtn.textContent = 'Resumir análise';
      resumirBtn.onclick = () => resumirAnalise(key);
      resultEl.parentNode.insertBefore(resumirBtn, resultEl.nextSibling);
    }
    resumirBtn.style.display = '';
  } catch (err) {
    resultEl.className = 'ai-result visible';
    resultEl.style.color = '#dc2626';
    resultEl.innerHTML = `Erro: ${err.message}`;
  }
}

async function resumirAnalise(key) {
  const resultEl = document.getElementById(`result${key}`);
  const texto = resultEl?.innerText?.trim();
  if (!texto) return;

  const btn = document.getElementById(`resumirAnaliseBtn${key}`);
  btn.disabled = true;
  btn.textContent = 'Resumindo…';

  try {
    const resp = await fetch('/api/ia', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'claude-haiku-4-5-20251001',
        max_tokens: 1024,
        system: 'Você é fisioterapeuta. Resuma a análise abaixo de forma objetiva, mantendo apenas os achados clinicamente mais relevantes e as sugestões de abordagem. Sem introduções. Direto ao ponto. Use <strong>...</strong> para negritos. Não use asteriscos.',
        messages: [{ role: 'user', content: texto }]
      })
    });

    if (!resp.ok) {
      const err = await resp.json().catch(() => ({}));
      throw new Error(err.error?.message || `Erro ${resp.status}`);
    }

    const data = await resp.json();
    const resumo = data.content?.[0]?.text || '';
    if (!resumo) throw new Error('Sem resposta da IA');

    if (confirm('Substituir a análise pelo resumo?')) {
      resultEl.innerHTML = resumo.replace(/\n/g, '<br>');
      salvarRascunho();
    }
  } catch (err) {
    showToast('Erro ao resumir: ' + err.message);
  } finally {
    btn.disabled = false;
    btn.textContent = 'Resumir análise';
  }
}

// ── Coleta dados da avaliação ─────────────────────────────────
function coletarDadosAvaliacao() {
  const v   = id  => (document.getElementById(id)?.value       || '').trim();
  const txt = id  => (document.getElementById(id)?.textContent || '').trim();
  const lines = [];
  const add = (label, value) => { if (value) lines.push(`${label}: ${value}`); };

  lines.push('=== ANAMNESE ===');
  add('Paciente',              v('nomeCompleto'));
  add('Idade',                 v('idade'));
  add('Profissão',             v('profissao'));
  add('Objetivo',              v('objetivo'));
  add('Queixa principal',      v('queixaPrincipal'));
  add('HDA',                   v('hda'));
  add('Diagnóstico clínico',   v('diagnostico'));
  add('Classificação CBDF',    v('codigoCBDF'));
  add('Exames complementares', v('exames'));
  add('Antecedentes',          v('app'));
  add('Outros sintomas',       v('outrosSintomas'));
  add('Medicamentos',          v('medicamentos'));
  add('AVDs',                  v('avds'));
  add('Sono',                  v('sono'));
  add('Alimentação',           v('alimentacao'));
  add('Atividade física', document.querySelector('input[name="atividadeFisica"]:checked')?.value);
  add('Outros hábitos',        v('outrosHabitos'));

  lines.push('');
  lines.push('=== ANÁLISE DA DOR ===');
  const evaBtn = document.querySelector('.eva-btn.active');
  if (evaBtn) add('EVA', `${evaBtn.dataset.val}/10 – ${txt('evaDesc')}`);
  const nMarkers = document.querySelectorAll('.body-marker').length;
  if (nMarkers) add('Mapa corporal', `${nMarkers} ponto(s) de dor marcado(s)`);
  add('Frequência',  document.querySelector('.toggle-btn.active[data-group="frequencia"]')?.dataset.value);
  const tipos = [...document.querySelectorAll('.toggle-btn.active[data-group="tipoDor"]')].map(b => b.dataset.value).join(', ');
  add('Tipo de dor', tipos);
  add('Piora com',   v('piora'));
  add('Melhora com', v('melhora'));
  add('Horário de maior intensidade', document.querySelector('.toggle-btn.active[data-group="horario"]')?.dataset.value);
  const visVal = document.getElementById('horarioVisceral')?.value;
  if (visVal && visVal !== '' && visVal !== 'nao-se-aplica') add('Horário visceral', txt('visceralCardBody') || visVal);

  lines.push('');
  lines.push('=== ANÁLISE POSTURAL ===');
  ['Anterior', 'Posterior', 'LateralD', 'LateralE'].forEach(k => {
    const el = document.getElementById(`result${k}`);
    const t  = el?.textContent?.trim();
    if (t && el.classList.contains('visible') && !t.startsWith('Analisando')) add(`Vista ${k}`, t);
  });
  add('Observações posturais', v('obsPostural'));

  lines.push('');
  lines.push('=== CADEIAS MUSCULARES ===');
  ['Flexao','Extensao','FlexaoLatD','FlexaoLatE','RotacaoD','RotacaoE'].forEach(k => {
    const el = document.getElementById(`result${k}`);
    const t  = el?.textContent?.trim();
    if (t && el.classList.contains('visible') && !t.startsWith('Analisando')) add(k, t);
  });
  add('Observações cadeias',   v('obsCadeias'));
  add('Função diafragmática',  v('diafragma'));
  add('Transverso do abdômen', v('transverso'));

  lines.push('');
  lines.push('=== TESTES DE MOBILIDADE E ESTABILIDADE ARTICULAR ===');
  const _testKeys = [
    ['apley2','Apley – Alcance Superior','obs-apley2',['apley2-red-d','apley2-red-e']],
    ['apley3','Apley – Alcance Inferior','obs-apley3',['apley3-red-d','apley3-red-e']],
    ['grandeDorsal','Grande Dorsal','obs-grandeDorsal',[]],
    ['thomas1','Thomas – Reto Femoral','obs-thomas1',[]],
    ['thomas2','Thomas – Iliopsoas','obs-thomas2',[]],
    ['patrickCoxo','Patrick/FABER – Disfunção Coxofemoral','obs-patrickCoxo',[]],
    ['patrickSI','Patrick/FABER – Disfunção Sacro-Ilíaca','obs-patrickSI',[]],
    ['piriforme','Comprimento do Piriforme','obs-piriforme',[]],
    ['ober','Ober – TI-IT','obs-ober',[]],
    ['abducaoQuadril','Abdução do Quadril','obs-abducaoQuadril',[]],
    ['elevacaoPerna','Elevação da Perna Estendida','obs-elevacaoPerna',[]],
    ['stepDownTronco','Step Down – Controle de Tronco','obs-stepDownTronco',[]],
    ['stepDownTrendelenburg','Step Down – Sinal de Trendelenburg','obs-stepDownTrendelenburg',[]],
    ['stepDownValgo','Step Down – Valgo Dinâmico','obs-stepDownValgo',[]],
    ['stepDownPronacao','Step Down – Pronação do Tornozelo','obs-stepDownPronacao',[]],
    ['lunge','Lunge (Tornozelo)','obs-lunge',[]],
  ];
  _testKeys.forEach(([key, label, obsId, achados]) => {
    if (!testResults[key]) return;
    let val = testResults[key];
    const extra = achados.filter(a => testResults[a]).map(a => testResults[a]);
    if (extra.length) val += ' + ' + extra.join(' + ');
    add(label, val);
    const obs = v(obsId);
    if (obs) add(`  Observação`, obs);
  });
  // Discinesia (lados independentes)
  const discNeg = testResults['discinese-neg'];
  const discD = testResults['discinese-d'], discE = testResults['discinese-e'];
  if (discNeg || discD || discE) {
    if (discNeg) {
      add('Discinesia Escapular', 'Negativo');
    } else {
      const parts = [];
      if (discD) parts.push('Positivo D' + (testResults['discinese-tipo-d'] ? ` (${testResults['discinese-tipo-d']})` : ''));
      if (discE) parts.push('Positivo E' + (testResults['discinese-tipo-e'] ? ` (${testResults['discinese-tipo-e']})` : ''));
      add('Discinesia Escapular', parts.join(' + '));
    }
    const obsDisc = v('obs-discinese');
    if (obsDisc) add('  Observação', obsDisc);
  }
  // Lasègue (complementa Elevação da Perna Estendida)
  const _lasegueKeys = [['lasegue-d','Positivo D'],['lasegue-e','Positivo E'],['lasegue-de','Positivo D e E'],['lasegue-cruzado','Cruzado']];
  const _lasParts = _lasegueKeys.filter(([k]) => testResults[k]).map(([,label]) => label);
  if (_lasParts.length) add('  Sinal de Lasègue', _lasParts.join(' + '));

  add('Observações gerais dos testes', v('obsTestes'));

  return lines.join('\n');
}

let storedPlanoHTML = '';
const COVER_PHOTO_B64 = 'data:image/jpeg;base64,';
const LOGO_WATERMARK_B64 = 'data:image/png;base64,';

// ── Gera plano de tratamento com IA ──────────────────────────
async function gerarPlanoTratamento() {
  const btn     = document.getElementById('btnGerarPlano');
  const wrapper = document.getElementById('planoResultWrapper');
  const ta      = document.getElementById('planoTratamento');

  btn.disabled    = true;
  btn.textContent = 'Gerando plano…';

  const resumo = coletarDadosAvaliacao();
  const prompt = `Você é fisioterapeuta especialista em Pilates Clínico. Elabore o plano de tratamento abaixo com base exclusivamente nos dados fornecidos.

Regras gerais: sem markdown, sem asteriscos, sem emojis, sem frases introdutórias ou recursos contextuais. Inicie direto pelo primeiro título. Use os títulos exatamente como indicados abaixo, em letras maiúsculas, seguidos de dois-pontos e quebra de linha. Documento clínico objetivo para impressão.

DADOS DA AVALIAÇÃO:
${resumo}

Estrutura obrigatória:

OBJETIVOS TERAPÊUTICOS:
(lista numerada com cada objetivo em item separado)

FUNDAMENTAÇÃO CLÍNICA:
(texto corrido, 3-5 linhas, conectando os achados entre si)

EXERCÍCIOS RECOMENDADOS:
Fase 1 – Básico (semanas 1-4):
(lista numerada dos exercícios com breve justificativa de cada um)
Fase 2 – Intermediário (semanas 5-8):
(lista numerada)
Fase 3 – Avançado (a partir da semana 9):
(lista numerada)

FREQUÊNCIA SEMANAL E DURAÇÃO:
(texto direto: número de sessões, duração, prazo de reavaliação)

PONTOS DE ATENÇÃO E CONTRAINDICAÇÕES:
(lista com hífen, um ponto por linha)

PRIORIDADES PARA AS PRIMEIRAS SESSÕES:
(lista numerada, do mais urgente ao menos urgente)

Regra de rigor: utilize apenas os dados fornecidos. Se algum dado relevante estiver ausente, indique que a análise fica prejudicada. Não invente achados. Responda em português.`;

  try {
    const resp = await fetch('/api/ia', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'claude-opus-4-8',
        max_tokens: 16000,
        messages: [{ role: 'user', content: prompt }]
      })
    });

    if (!resp.ok) {
      const err = await resp.json().catch(() => ({}));
      throw new Error(err.error?.message || `Erro ${resp.status}`);
    }

    const data = await resp.json();
    const planText = data.content?.[0]?.text || 'Sem resposta.';
    storedPlanoHTML = ta.innerHTML = planText.replace(/\n/g, '<br>');
    console.log('[gerarPlano] storedPlanoHTML definido, length:', storedPlanoHTML.length);
    injectFormatBar(ta);
    salvarRascunho();
    wrapper.style.display = 'block';
    wrapper.scrollIntoView({ behavior: 'smooth', block: 'start' });
  } catch (err) {
    showToast(`Erro ao gerar plano: ${err.message}`);
  } finally {
    btn.disabled    = false;
    btn.textContent = 'Gerar Plano de Tratamento com IA';
  }
}

