// Limpa espaços extras ao colar texto no campo de exames (comum em cópias de PDF)
document.getElementById('exames').addEventListener('paste', function(e) {
  e.preventDefault();
  const texto = (e.clipboardData || window.clipboardData).getData('text');
  const limpo = texto
    .split('\n')
    .map(linha => linha.replace(/\s{2,}/g, ' ').trim())
    .join('\n')
    .trim();
  const start = this.selectionStart;
  const end   = this.selectionEnd;
  this.value  = this.value.substring(0, start) + limpo + this.value.substring(end);
  this.selectionStart = this.selectionEnd = start + limpo.length;
  this.dispatchEvent(new Event('input'));
});

async function resumirHda() {
  const ta = document.getElementById('hda');
  const texto = ta.value.trim();
  if (!texto) return;

  const btn = document.getElementById('btnResumirHda');
  btn.disabled = true;
  btn.textContent = 'Resumindo…';

  try {
    const resp = await fetch('/api/ia', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'claude-haiku-4-5-20251001',
        max_tokens: 1024,
        system: 'Você é fisioterapeuta. Resuma o seguinte relato do paciente de forma clara e objetiva, mantendo apenas as informações clinicamente relevantes, em português. Sem introduções. Direto ao ponto.',
        messages: [{ role: 'user', content: texto }]
      })
    });

    if (!resp.ok) {
      const err = await resp.json().catch(() => ({}));
      throw new Error(err.error?.message || `Erro ${resp.status}`);
    }

    const data = await resp.json();
    const resumo = data.content?.[0]?.text || '';
    if (!resumo) throw new Error('Sem resposta da IA');

    if (confirm('Substituir o texto atual pelo resumo?')) {
      ta.value = resumo;
      ta.dispatchEvent(new Event('input'));
    }
  } catch (err) {
    showToast('Erro ao resumir: ' + err.message);
  } finally {
    btn.disabled = false;
    btn.textContent = 'Resumir';
  }
}

// ── Transcrição de voz (HDA) ──────────────────────────────────
let _hdaRec = null, _hdaWant = false;

function toggleHdaVoz() {
  const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
  if (!SR) { showToast('Reconhecimento de voz não suportado. Use Chrome ou Edge.'); return; }
  if (location.protocol === 'file:') { showToast('Voz requer HTTP. Abra pelo Live Server ou use o deploy do Netlify.'); return; }

  const btn = document.getElementById('btnMicHda');

  if (_hdaWant) {
    _hdaWant = false;
    _hdaRec?.abort();
    btn.classList.remove('active');
    return;
  }

  const ta     = document.getElementById('hda');
  const prefix = ta.value.trimEnd();
  let acumulado = '';

  _hdaWant = true;
  btn.classList.add('active');

  function rodada() {
    if (!_hdaWant) return;

    const rec = new SR();       // nova instância a cada rodada — obrigatório no Chrome
    _hdaRec = rec;
    rec.lang            = 'pt-BR';
    rec.continuous      = false; // reiniciamos manualmente
    rec.interimResults  = true;
    rec.maxAlternatives = 1;

    rec.onaudiostart = () => console.log('[voz] áudio capturado');
    rec.onspeechstart = () => console.log('[voz] fala detectada');
    rec.onspeechend   = () => console.log('[voz] fala encerrada');

    rec.onresult = e => {
      let interim = '';
      for (let i = e.resultIndex; i < e.results.length; i++) {
        if (e.results[i].isFinal) acumulado += e.results[i][0].transcript;
        else interim += e.results[i][0].transcript;
      }
      ta.value = (prefix ? prefix + ' ' : '') + acumulado + interim;
      ta.dispatchEvent(new Event('input'));
    };

    rec.onend = () => {
      console.log('[voz] onend, _hdaWant=', _hdaWant);
      if (_hdaWant) { setTimeout(rodada, 150); return; }
      btn.classList.remove('active');
      ta.value = ((prefix ? prefix + ' ' : '') + acumulado).trim();
      ta.dispatchEvent(new Event('input'));
    };

    rec.onerror = e => {
      console.log('[voz] onerror:', e.error);
      if (e.error === 'aborted' || e.error === 'no-speech') return;
      _hdaWant = false;
      btn.classList.remove('active');
      const msgs = {
        'not-allowed':         'Permissão de microfone negada. Permita nas configurações do Chrome.',
        'network':             'Erro de rede ao acessar o serviço de voz do Google.',
        'service-not-allowed': 'Serviço de voz bloqueado pelo navegador.',
        'audio-capture':       'Microfone não encontrado ou inacessível.',
      };
      showToast(msgs[e.error] || `Erro de voz: ${e.error}`);
    };

    try {
      rec.start();
      console.log('[voz] start() chamado');
    } catch (err) {
      console.error('[voz] erro no start():', err);
      showToast('Erro ao iniciar: ' + err.message);
      _hdaWant = false;
      btn.classList.remove('active');
    }
  }

  rodada();
}

// ── Toast ─────────────────────────────────────────────────────
function showToast(msg) {
  const toast = document.getElementById('toast');
  toast.textContent = msg;
  toast.classList.add('show');
  setTimeout(() => toast.classList.remove('show'), 3500);
}

// ── Auto-save com localStorage ────────────────────────────────
const DRAFT_KEY = 'anga_rascunho_v1';

const _FIELD_IDS = [
  'nomeCompleto','dataNascimento','ocupacao','fisioterapeuta','fisioterapeutaCrefito','dataAvaliacao',
  'objetivo','queixaPrincipal','hda','diagnostico','codigoCBDF','exames','app','outrosSintomas','medicamentos',
  'avds','sono','alimentacao','outrosHabitos',
  'piora','melhora','horarioVisceral',
  'obsPostural',
  'obsCadeias','diafragma','transverso',
  'obsTestes',
  'linkVedius',
  'footerFisio','footerCrefito','footerData','footerLocalizacao',
  'obs-apley2','obs-apley3','obs-discinese','obs-grandeDorsal',
  'obs-thomas1','obs-thomas2','obs-patrickCoxo','obs-patrickSI','obs-piriforme','obs-ober','obs-abducaoQuadril','obs-elevacaoPerna',
  'obs-stepDownTronco','obs-stepDownTrendelenburg','obs-stepDownValgo','obs-stepDownPronacao',
  'obs-lunge',
];

const _PHOTO_KEYS = ['Anterior','LateralD','LateralE','Posterior','Flexao','Extensao','FlexaoLatD','FlexaoLatE','RotacaoD','RotacaoE'];

function _coletarRascunho(incluirFotos) {
  const d = {};
  _FIELD_IDS.forEach(id => { const el = document.getElementById(id); if (el) d[id] = el.value; });
  const rf = document.querySelector('input[name="atividadeFisica"]:checked');
  if (rf) d.atividadeFisica = rf.value;
  d.toggles = {};
  document.querySelectorAll('.toggle-btn.active').forEach(b => { d.toggles[b.dataset.group] = b.dataset.value; });
  const evaActive = document.querySelector('.eva-btn.active');
  d.eva = evaActive ? evaActive.dataset.val : null;
  d.testResults = { ...testResults };
  d.bodyMarkers = [];
  document.querySelectorAll('.body-marker').forEach(m => {
    d.bodyMarkers.push({ cx: m.getAttribute('cx'), cy: m.getAttribute('cy') });
  });
  d.aiResults = {};
  _PHOTO_KEYS.forEach(k => { const el = document.getElementById(`result${k}`); if (el && el.innerHTML.trim()) d.aiResults[k] = el.innerHTML; });
  d.planoHTML = document.getElementById('planoTratamento')?.innerHTML || storedPlanoHTML || '';
  if (incluirFotos) {
    d.fotos = {};
    _PHOTO_KEYS.forEach(k => { if (photoData[k]) d.fotos[k] = { dataUrl: photoData[k].dataUrl, mimeType: photoData[k].mimeType }; });
  }
  return d;
}

function salvarRascunho() {
  try {
    localStorage.setItem(DRAFT_KEY, JSON.stringify(_coletarRascunho(true)));
  } catch {
    try {
      localStorage.setItem(DRAFT_KEY, JSON.stringify(_coletarRascunho(false)));
    } catch (e) { console.warn('[auto-save] Não foi possível salvar:', e.message); }
  }
}

function restaurarRascunho() {
  const raw = localStorage.getItem(DRAFT_KEY);
  if (!raw) return;
  let d;
  try { d = JSON.parse(raw); } catch { return; }

  _FIELD_IDS.forEach(id => {
    if (d[id] == null) return;
    const el = document.getElementById(id);
    if (el) el.value = d[id];
  });

  if (d.atividadeFisica) {
    const r = document.querySelector(`input[name="atividadeFisica"][value="${d.atividadeFisica}"]`);
    if (r) r.checked = true;
  }

  if (d.toggles) {
    Object.entries(d.toggles).forEach(([group, val]) => {
      document.querySelectorAll(`.toggle-btn[data-group="${group}"]`).forEach(b => b.classList.remove('active'));
      document.querySelector(`.toggle-btn[data-group="${group}"][data-value="${val}"]`)?.classList.add('active');
    });
  }

  if (d.eva != null) {
    document.querySelectorAll('.eva-btn').forEach(b => b.classList.remove('active'));
    const eb = document.querySelector(`.eva-btn[data-val="${d.eva}"]`);
    if (eb) {
      eb.classList.add('active');
      const desc = document.getElementById('evaDesc');
      if (desc) desc.textContent = EVA_DESC[parseInt(d.eva)] || '';
    }
  }

  if (d.testResults) {
    Object.entries(d.testResults).forEach(([test, val]) => {
      testResults[test] = val;
      document.querySelector(`.result-btn[data-test="${test}"][data-val="${val}"]`)?.classList.add('active');
    });
    // Restaura visibilidade das linhas de Tipo da Discinesia
    if (testResults['discinese-d']) document.getElementById('discinese-tipo-d')?.classList.remove('hidden');
    if (testResults['discinese-e']) document.getElementById('discinese-tipo-e')?.classList.remove('hidden');
  }

  if (d.bodyMarkers?.length && svgOverlay) {
    d.bodyMarkers.forEach(({ cx, cy }) => {
      const dot = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
      dot.setAttribute('cx', cx); dot.setAttribute('cy', cy);
      dot.setAttribute('r', '6'); dot.setAttribute('fill', '#c25609');
      dot.setAttribute('stroke', '#fff'); dot.setAttribute('stroke-width', '1.5');
      dot.classList.add('body-marker');
      svgOverlay.appendChild(dot);
    });
  }

  if (d.aiResults) {
    Object.entries(d.aiResults).forEach(([k, html]) => {
      const el = document.getElementById(`result${k}`);
      if (el) el.innerHTML = html;
    });
  }

  if (d.planoHTML) {
    storedPlanoHTML = d.planoHTML;
    const planoEl = document.getElementById('planoTratamento');
    if (planoEl) planoEl.innerHTML = d.planoHTML;
    const wrapper = document.getElementById('planoResultWrapper');
    if (wrapper) wrapper.style.display = 'block';
  }

  if (d.fotos) {
    Object.entries(d.fotos).forEach(([key, data]) => {
      photoData[key] = { dataUrl: data.dataUrl, base64: data.dataUrl.split(',')[1], mimeType: data.mimeType };
      const preview = document.getElementById(`preview${key}`);
      const placeholder = document.getElementById(`placeholder${key}`);
      if (preview) { preview.src = data.dataUrl; preview.style.display = 'block'; }
      if (placeholder) placeholder.style.display = 'none';
    });
  }

  // Reaciona visceral card caso horário foi restaurado
  const visEl = document.getElementById('horarioVisceral');
  if (visEl?.value && VISCERAL_MAP[visEl.value]) {
    document.getElementById('visceralCardBody').textContent = VISCERAL_MAP[visEl.value];
    document.getElementById('visceralCard').style.display = 'block';
  }
}

function limparRascunho() {
  if (!confirm('Limpar todos os dados e começar uma avaliação nova?')) return;
  localStorage.removeItem(DRAFT_KEY);
  location.reload();
}

let _saveTimer = null;
function _agendarSave() { clearTimeout(_saveTimer); _saveTimer = setTimeout(salvarRascunho, 1000); }
document.addEventListener('input', _agendarSave);
document.addEventListener('change', _agendarSave);
document.addEventListener('click', e => {
  if (e.target.closest('.toggle-btn,.result-btn,.eva-btn')) _agendarSave();
});

